	boolean isCertainCrossJoin(CrossJoinSummary leftSummary, CrossJoinSummary rightSummary,
			Map<String, CrossJoinToken> joinIncomingContext, Map<String, CrossJoinToken> rightContext) {
		if (leftSummary.definitelyEmpty() || rightSummary.definitelyEmpty()) {
			return false;
		}
		Set<String> shared = new LinkedHashSet<>(leftSummary.mayVars());
		shared.retainAll(rightSummary.mayVars());
		if (shared.isEmpty()) {
			return !leftSummary.dependsOnExternalBindings()
					&& !rightSummary.dependsOnExternalBindings()
					&& !leftSummary.dependsOn(joinIncomingContext)
					&& !rightSummary.dependsOn(joinIncomingContext);
		}
		for (String varName : shared) {
			CrossJoinToken rightToken = rightSummary.key().get(varName);
			if (rightToken == null) {
				return false;
			}
			CrossJoinToken leftToken = leftSummary.key().get(varName);
			if (leftToken != null && rightToken.equals(leftToken) && !rightToken.isExternalInput()) {
				continue;
			}
			CrossJoinToken contextToken = rightContext.get(varName);
			if (leftSummary.alwaysVars().contains(varName) && contextToken != null && rightToken.equals(contextToken)
					&& !contextToken.isExternalInput()) {
				continue;
			}
			return false;
		}
		return true;
	}

	private CrossJoinToken extensionToken(CrossJoinSummary currentSummary, ValueExpr expression) {
		if (expression instanceof ValueConstant) {
			return CrossJoinToken.constant(((ValueConstant) expression).getValue());
		}
		if (expression instanceof Var) {
			Var var = (Var) expression;
			if (var.hasValue()) {
				return CrossJoinToken.constant(var.getValue());
			}
			return currentSummary.tokenFor(var.getName());
		}
		return null;
	}
